recommended_query_pattern.sparql:
# Try 201211 first
SELECT ?cgi_iri ?label WHERE {
  glosis_cl:lithologyValueCode-XX skos:exactMatch|skos:closeMatch ?cgi_iri .
  ?cgi_iri rdfs:label ?label .
} LIMIT 1
# If no result, try 2016.01:
SELECT ?cgi_iri ?label WHERE {
  glosis_cl:lithologyValueCode-XX skos:closeMatch ?cgi_iri .
  ?cgi_iri rdfs:isDefinedBy <http://resource.geosciml.org/classifierscheme/cgi/2016.01/simplelithology> .
}
